use wasm_bindgen::prelude::*;

/// 简单加法 — 演示基本类型映射
#[wasm_bindgen]
pub fn add(a: i32, b: i32) -> i32 {
    a + b
}

/// 斐波那契 — 演示递归和数值计算
#[wasm_bindgen]
pub fn fibonacci(n: u32) -> u64 {
    match n {
        0 => 0,
        1 => 1,
        _ => {
            let mut a: u64 = 0;
            let mut b: u64 = 1;
            for _ in 2..=n {
                let temp = a + b;
                a = b;
                b = temp;
            }
            b
        }
    }
}

/// 数组求和 — 演示切片引用（零拷贝）
#[wasm_bindgen]
pub fn sum_array(data: &[f64]) -> f64 {
    data.iter().sum()
}

/// 初始化（设置 panic hook）
#[wasm_bindgen(start)]
pub fn init() {
    console_error_panic_hook::set_once();
}

// JS 版本的斐波那契
function jsFibonacci(n) {
    let a = 0, b = 1;
    for (let i = 2; i <= n; i++) {
        [a, b] = [b, a + b];
    }
    return b;
}

// JS 版本的数组求和
function jsSumArray(data) {
    let sum = 0;
    for (let i = 0; i < data.length; i++) {
        sum += data[i];
    }
    return sum;
}

async function benchmark() {
    await init();

    // 测试 1: 斐波那契
    const N = 45;
    const iterations = 100;

    let start = performance.now();
    for (let i = 0; i < iterations; i++) jsFibonacci(N);
    const jsTime = performance.now() - start;

    start = performance.now();
    for (let i = 0; i < iterations; i++) fibonacci(N);
    const wasmTime = performance.now() - start;

    console.log(`Fibonacci(${N}) x${iterations}:`);
    console.log(`  JS:   ${jsTime.toFixed(2)}ms`);
    console.log(`  WASM: ${wasmTime.toFixed(2)}ms`);
    console.log(`  加速比: ${(jsTime / wasmTime).toFixed(1)}x`);

    // 测试 2: 数组求和
    const arr = new Float64Array(1_000_000);
    for (let i = 0; i < arr.length; i++) arr[i] = Math.random();

    start = performance.now();
    for (let i = 0; i < 100; i++) jsSumArray(arr);
    const jsTime2 = performance.now() - start;

    start = performance.now();
    for (let i = 0; i < 100; i++) sum_array(arr);
    const wasmTime2 = performance.now() - start;

    console.log(`\nArray sum (1M elements) x100:`);
    console.log(`  JS:   ${jsTime2.toFixed(2)}ms`);
    console.log(`  WASM: ${wasmTime2.toFixed(2)}ms`);
    console.log(`  加速比: ${(jsTime2 / wasmTime2).toFixed(1)}x`);
}
